create table dirkspzm32.ts_resources_cfg (
    sid            varchar2(2 char) default '01' not null enable,
    firma_nr       number(6, 0) default 1 not null enable,
    sched_res_id   number(*, 0) not null enable,
    sched_res_name varchar2(50 char) not null enable,
    enabled        varchar2(1 char) default 'F' not null enable,
    group_id       number(*, 0) default 0 not null enable,
    hostname       varchar2(150 char),
    app_exename    varchar2(150 char) default 'ISIPLUSTASKSERVICE.EXE' not null enable,
    sched_type     varchar2(50 char) default 'SCHED_TYPE_TASK_SERVICE' not null enable,
    instance_id    number(*, 0) default 1 not null enable
);

alter table dirkspzm32.ts_resources_cfg
    add constraint pk_ts_resources_cfg
        primary key ( sid,
                      firma_nr,
                      sched_res_id )
            using index enable;


